import{_ as t,c as r,o as d,a4 as a}from"./chunks/framework.I1cCAST3.js";const o="/assets/terminal_tab.BxR_5N35.png",p=JSON.parse('{"title":"终端管理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/manage/index.md","filePath":"docs/terminal/manage/index.md"}'),e={name:"docs/terminal/manage/index.md"},n=a('<h1 id="终端管理" tabindex="-1">终端管理 <a class="header-anchor" href="#终端管理" aria-label="Permalink to &quot;终端管理&quot;">​</a></h1><p>管理多个终端会话，通过标签页和分屏组织您的工作区，保持工作流高效运转。</p><p><img src="'+o+'" alt=""></p><h2 id="标签菜单栏操作" tabindex="-1">标签菜单栏操作 <a class="header-anchor" href="#标签菜单栏操作" aria-label="Permalink to &quot;标签菜单栏操作&quot;">​</a></h2><p>右键点击标签或使用标签菜单栏可以执行以下操作：</p><table tabindex="0"><thead><tr><th>操作</th><th>功能</th><th>使用场景</th></tr></thead><tbody><tr><td><strong>关闭</strong></td><td>关闭当前终端会话</td><td>任务完成后不再需要该会话时</td></tr><tr><td><strong>关闭其他</strong></td><td>关闭除当前焦点之外的所有会话</td><td>工作区杂乱，只想保留当前会话时</td></tr><tr><td><strong>全部关闭</strong></td><td>关闭所有打开的终端会话</td><td>切换工作场景或结束工作时</td></tr><tr><td><strong>克隆</strong></td><td>将当前会话复制到新标签页</td><td>需要在同一主机上开启第二个会话时</td></tr><tr><td><strong>向右分屏</strong></td><td>在右侧创建水平分屏窗格</td><td>需要并排终端时（例如：日志 + 命令）</td></tr><tr><td><strong>向下分屏</strong></td><td>在下方创建垂直分屏窗格</td><td>需要上下叠放终端时（例如：监控 + 操作）</td></tr></tbody></table><h2 id="右键菜单功能" tabindex="-1">右键菜单功能 <a class="header-anchor" href="#右键菜单功能" aria-label="Permalink to &quot;右键菜单功能&quot;">​</a></h2><p>在终端任意位置右键点击可访问上下文菜单，包含以下选项：</p><h3 id="基础操作" tabindex="-1">基础操作 <a class="header-anchor" href="#基础操作" aria-label="Permalink to &quot;基础操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>复制</strong></td><td>将选中的文本复制到剪贴板</td></tr><tr><td><strong>粘贴</strong></td><td>将剪贴板内容粘贴到终端</td></tr><tr><td><strong>搜索</strong></td><td>打开搜索栏，在终端输出中查找文本</td></tr><tr><td><strong>清屏</strong></td><td>清除当前终端中所有可见输出</td></tr><tr><td><strong>文件管理</strong></td><td>打开以终端工作目录为根目录的文件管理器</td></tr><tr><td><strong>字体大小</strong></td><td>放大或缩小终端字体</td></tr></tbody></table><h3 id="连接管理" tabindex="-1">连接管理 <a class="header-anchor" href="#连接管理" aria-label="Permalink to &quot;连接管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>断开连接</strong></td><td>断开当前终端的 SSH 连接</td></tr><tr><td><strong>新终端</strong></td><td>打开全新的终端会话</td></tr><tr><td><strong>关闭终端</strong></td><td>关闭当前终端会话</td></tr></tbody></table><h3 id="分屏操作" tabindex="-1">分屏操作 <a class="header-anchor" href="#分屏操作" aria-label="Permalink to &quot;分屏操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>向右分屏</strong></td><td>创建水平分屏窗格</td></tr><tr><td><strong>向下分屏</strong></td><td>创建垂直分屏窗格</td></tr></tbody></table><h2 id="终端管理技巧" tabindex="-1">终端管理技巧 <a class="header-anchor" href="#终端管理技巧" aria-label="Permalink to &quot;终端管理技巧&quot;">​</a></h2><ol><li><strong>将分屏用于相关任务</strong> -- 一侧查看日志，另一侧执行命令。详情请参阅<a href="/docs/terminal/operations/">终端操作</a>。</li><li><strong>重命名标签页</strong> -- 右键点击标签并重命名，以便快速识别会话。</li><li><strong>关闭不需要的会话</strong> -- 未使用的会话会占用资源。使用 <strong>关闭其他</strong> 或 <strong>全部关闭</strong> 来整理工作区。</li><li><strong>借助 AI</strong> -- 让 <a href="/docs/terminal/chattoai/">Chat to AI</a> 生成命令，这样您可以专注于结果而非语法。</li></ol><div class="warning custom-block"><p class="custom-block-title">重要提示</p><ul><li>终端操作需要在远程主机上拥有相应权限。</li><li>执行命令前请仔细检查，特别是在生产服务器上。</li><li>请先在测试环境中验证有风险的操作。</li></ul></div>',17),s=[n];function i(l,h,g,c,b,_){return d(),r("div",null,s)}const u=t(e,[["render",i]]);export{p as __pageData,u as default};
